// PharmaBill Service Worker — auto-versioned per build
// BUILD_VERSION is read from /build-version.json (generated by Vite plugin on every build)

let CACHE_NAME = 'pharmabill-init';
let BUILD_VERSION = null;

async function fetchBuildVersion() {
  try {
    const res = await fetch('/build-version.json', { cache: 'no-store' });
    if (!res.ok) return null;
    const data = await res.json();
    return data.v ? String(data.v) : null;
  } catch {
    return null;
  }
}

self.addEventListener('install', event => {
  event.waitUntil(
    (async () => {
      const v = await fetchBuildVersion();
      if (v) {
        BUILD_VERSION = v;
        CACHE_NAME = `pharmabill-${v}`;
      }
      const cache = await caches.open(CACHE_NAME);
      await cache.addAll(['/', '/index.html', '/manifest.json']);
      self.skipWaiting();
    })()
  );
});

self.addEventListener('activate', event => {
  event.waitUntil(
    (async () => {
      // Delete all old caches that don't match the current CACHE_NAME
      const keys = await caches.keys();
      await Promise.all(
        keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k))
      );
      await self.clients.claim();
      // Notify all clients that a new SW version is active
      const allClients = await self.clients.matchAll({ includeUncontrolled: true });
      for (const client of allClients) {
        client.postMessage({ type: 'SW_UPDATED' });
      }
    })()
  );
});

self.addEventListener('fetch', event => {
  // Never intercept non-GET requests
  if (event.request.method !== 'GET') return;

  const url = new URL(event.request.url);

  // Always fetch build-version.json fresh from network — never cache it
  if (url.pathname === '/build-version.json') {
    event.respondWith(fetch(event.request, { cache: 'no-store' }));
    return;
  }

  // For navigation requests, do a background version check after responding
  if (event.request.mode === 'navigate') {
    event.respondWith(
      fetch(event.request).catch(() => caches.match(event.request) || caches.match('/'))
    );
    // Background version check — triggers new SW install cycle if version changed
    event.waitUntil(
      (async () => {
        try {
          const v = await fetchBuildVersion();
          if (v && v !== BUILD_VERSION) {
            await self.registration.update();
          }
        } catch {
          // ignore — best effort
        }
      })()
    );
    return;
  }

  // Network-first for all other GET requests, fall back to cache
  event.respondWith(
    fetch(event.request)
      .then(response => {
        // Cache successful responses for offline fallback
        if (response && response.status === 200 && response.type === 'basic') {
          const responseClone = response.clone();
          caches.open(CACHE_NAME).then(cache => cache.put(event.request, responseClone));
        }
        return response;
      })
      .catch(() => caches.match(event.request))
  );
});
